// containerAWFServiceRoutingCheckCommand verifies the runner container has a
// PREROUTING bypass rule that exempts AWF subnet traffic targeting local IPs
// from inner dockerd's DOCKER chain DNAT. Match by source CIDR + addrtype LOCAL,
// not the literal `-j RETURN`, so the check stays robust against minor variants.
func containerAWFServiceRoutingCheckCommand(outerContainer string) string {
	q := strconv.Quote(outerContainer)
	return `docker exec ` + q + ` sh -c 'iptables -t nat -S PREROUTING 2>/dev/null | grep -E "(^|[[:space:]])-A PREROUTING([[:space:]]+.*)?[[:space:]]+-s[[:space:]]+172\.30\.0\.0/24([[:space:]]+.*)?[[:space:]]+-m[[:space:]]+addrtype([[:space:]]+.*)?[[:space:]]+--dst-type[[:space:]]+LOCAL([[:space:]]+.*)?[[:space:]]+-j[[:space:]]+RETURN" >/dev/null'`
}

